mapper.select:
SELECT g.idx AS groupId, g.name AS groupName, g.up_idx AS parentId, CASE WHEN g.up_idx = '#' OR g.up_idx IS NULL THEN '최상위' ELSE IFNULL(pg.name, '-') END AS parentGroupName, g.degree AS sortOrder, g.type AS groupType, g.regdate AS regDate, IFNULL(tc.targetCount, 0) AS targetCount FROM pi_target_group g LEFT JOIN pi_target_group pg ON pg.idx = g.up_idx AND pg.type IN (99, 98) LEFT JOIN ( SELECT tg2.up_idx, COUNT(*) AS targetCount FROM pi_target_group tg2 INNER JOIN pi_targets pt ON tg2.TARGET_ID = pt.TARGET_ID AND pt.TARGET_USE = 'Y' WHERE tg2.TARGET_ID IS NOT NULL GROUP BY tg2.up_idx ) tc ON tc.up_idx = g.idx WHERE g.type IN (99, 98)
AND g.name LIKE CONCAT('%', #{searchKeyword}, '%')
ORDER BY g.degree, g.name LIMIT #{offset}, #{limit}

mapper.update:
UPDATE pi_target_group
SET name = #{groupName}
WHERE idx = #{groupId}

mapper.select:
SELECT COUNT(*)
FROM pi_target_group
WHERE up_idx = #{groupId}
